import React, { useState, useEffect } from 'react';
import {
  Card,
  Table,
  Button,
  Tag,
  Modal,
  Form,
  Input,
  Statistic,
  Row,
  Col,
  message,
  Space,
  Popconfirm,
  Typography,
} from 'antd';
import {
  PlusOutlined,
  PlayCircleOutlined,
  PauseCircleOutlined,
  QrcodeOutlined,
} from '@ant-design/icons';
import { QRCodeSVG } from 'qrcode.react';
import {
  getPeriods,
  createPeriod,
  closePeriod,
  activatePeriod,
  getStatistics,
} from '@/services/api';

const { Title, Text } = Typography;

const DashboardPage: React.FC = () => {
  const [periods, setPeriods] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [createModalOpen, setCreateModalOpen] = useState(false);
  const [qrModalOpen, setQrModalOpen] = useState(false);
  const [statistics, setStatistics] = useState<any>(null);
  const [activePeriodId, setActivePeriodId] = useState<number | null>(null);
  const [form] = Form.useForm();

  useEffect(() => {
    loadPeriods();
  }, []);

  const loadPeriods = async () => {
    try {
      setLoading(true);
      const res: any = await getPeriods();
      if (res.code === 0) {
        setPeriods(res.data);
        // 找到活跃的周期并加载统计
        const active = res.data.find((p: any) => p.status === 'active');
        if (active) {
          setActivePeriodId(active.id);
          loadStatistics(active.id);
        }
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const loadStatistics = async (periodId: number) => {
    try {
      const res: any = await getStatistics(periodId);
      if (res.code === 0) {
        setStatistics(res.data);
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleCreate = async () => {
    try {
      const values = await form.validateFields();
      const res: any = await createPeriod({ title: values.title });
      if (res.code === 0) {
        message.success('创建成功');
        setCreateModalOpen(false);
        form.resetFields();
        loadPeriods();
      } else {
        message.error(res.message);
      }
    } catch (err) {
      // form validation error
    }
  };

  const handleClose = async (id: number) => {
    try {
      const res: any = await closePeriod(id);
      if (res.code === 0) {
        message.success('已关闭');
        loadPeriods();
      }
    } catch (err) {
      message.error('操作失败');
    }
  };

  const handleActivate = async (id: number) => {
    try {
      const res: any = await activatePeriod(id);
      if (res.code === 0) {
        message.success('已激活');
        loadPeriods();
      }
    } catch (err) {
      message.error('操作失败');
    }
  };

  const mobileUrl = `${window.location.origin}/mobile/submit`;

  const columns = [
    {
      title: '周期名称',
      dataIndex: 'title',
      key: 'title',
      render: (text: string) => <Text strong>{text}</Text>,
