              <Button
                type="link"
                danger
                icon={<PauseCircleOutlined />}
              >
                关闭
              </Button>
            </Popconfirm>
          ) : (
            <Popconfirm
              title="确认激活此采购周期？（当前活跃的周期将被关闭）"
              onConfirm={() => handleActivate(record.id)}
            >
              <Button type="link" icon={<PlayCircleOutlined />}>
                激活
              </Button>
            </Popconfirm>
          )}
        </Space>
      ),
    },
  ];

  return (
    <div>
      {/* 统计卡片 */}
      {statistics && activePeriodId && (
        <Row gutter={16} style={{ marginBottom: 24 }}>
