          </Col>
          <Col span={8}>
            <Card
              style={{ borderRadius: 12 }}
              bodyStyle={{ padding: '20px 24px' }}
            >
              <Statistic
                title="涉及品类数"
                value={statistics.categoryStats?.length || 0}
                valueStyle={{ color: '#faad14' }}
              />
            </Card>
          </Col>
        </Row>
      )}

      {/* 周期管理 */}
      <Card
        title={<Title level={5} style={{ margin: 0 }}>采购周期管理</Title>}
        extra={
          <Space>
            <Button
